mapper.select:
SELECT p.POST_ID AS postId, p.POST_TYPE AS postType, p.TITLE AS title, p.CONTENT AS content, p.CREATED_AT AS createdAt, p.UPDATED_AT AS updatedAt, p.VIEW_COUNT AS viewCount, COUNT(DISTINCT pl.POSTLIKE_ID) as likeCount, EXISTS(SELECT 1 FROM POST_LIKE pl2 WHERE pl2.POST_ID = #{postId}
AND pl2.vid = #{vid}
AND pl2.likedMemberId = #{memberId}
AND 0
) as isLiked FROM POST p LEFT JOIN POST_LIKE pl ON p.POST_ID = pl.POST_ID WHERE p.POST_ID = #{postId} GROUP BY p.POST_ID, p.POST_TYPE, p.TITLE, p.CONTENT, p.CREATED_AT, p.UPDATED_AT, p.VIEW_COUNT
